sys_ui_page.client_script:
// dialog_button id="cancel" was clicked, user does not want to delete the task
function onCancel() {
    // below will auto close popup
    GlideDialogWindow.get().destroy();
    return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to delete the task
function onSubmit() {
    return true;
}

sys_ui_page.processing_script:
deleteTask();

function deleteTask() {
	// DFCT0010541
	var url = 'x_153465_discovert_route_task_instance.do?sys_id=' + sysid;
    var gr = new GlideRecord("x_153465_discovert_route_task_instance");
    gr.addQuery('sys_id', sysid);
    gr.query();
    if (gr.next()) {
		// get URL before delete
		if(gr.parent){
			url = 'x_153465_discovert_route_task_instance.do?sys_id=' + gr.getValue('parent');
		} else {
			url = '/discovertaskerportal';
		}
        // Calls a Server function
        new Task_uiAction().uiAction_DeleteTasks(gr);
    }

	response.sendRedirect(url);
}
